            toStringOutput.Add($"CodeLength = {(this.CodeLength == null ? "null" : this.CodeLength.ToString())}");
            toStringOutput.Add($"LookupEnabled = {(this.LookupEnabled == null ? "null" : this.LookupEnabled.ToString())}");
            toStringOutput.Add($"Psd2Enabled = {(this.Psd2Enabled == null ? "null" : this.Psd2Enabled.ToString())}");
            toStringOutput.Add($"SkipSmsToLandlines = {(this.SkipSmsToLandlines == null ? "null" : this.SkipSmsToLandlines.ToString())}");
            toStringOutput.Add($"DtmfInputRequired = {(this.DtmfInputRequired == null ? "null" : this.DtmfInputRequired.ToString())}");
            toStringOutput.Add($"TtsName = {this.TtsName ?? "null"}");
            toStringOutput.Add($"DoNotShareWarningEnabled = {(this.DoNotShareWarningEnabled == null ? "null" : this.DoNotShareWarningEnabled.ToString())}");
            toStringOutput.Add($"CustomCodeEnabled = {(this.CustomCodeEnabled == null ? "null" : this.CustomCodeEnabled.ToString())}");
            toStringOutput.Add($"Push = {(this.Push == null ? "null" : this.Push.ToString())}");
            toStringOutput.Add($"Totp = {(this.Totp == null ? "null" : this.Totp.ToString())}");
            toStringOutput.Add($"DefaultTemplateSid = {this.DefaultTemplateSid ?? "null"}");
            toStringOutput.Add($"Whatsapp = {(this.Whatsapp == null ? "null" : this.Whatsapp.ToString())}");
            toStringOutput.Add($"Passkeys = {(this.Passkeys == null ? "null" : this.Passkeys.ToString())}");
            toStringOutput.Add($"VerifyEventSubscriptionEnabled = {(this.VerifyEventSubscriptionEnabled == null ? "null" : this.VerifyEventSubscriptionEnabled.ToString())}");
            toStringOutput.Add($"DateCreated = {(this.DateCreated == null ? "null" : this.DateCreated.ToString())}");
            toStringOutput.Add($"DateUpdated = {(this.DateUpdated == null ? "null" : this.DateUpdated.ToString())}");
            toStringOutput.Add($"Url = {this.Url ?? "null"}");
            toStringOutput.Add($"Links = {(this.Links == null ? "null" : this.Links.ToString())}");

            additionalProperties?
                .Select(kvp => $"[{kvp.Key}] = {kvp.Value.ToString(Formatting.None)}")
                .ToList()
                .ForEach(toStringOutput.Add);
        }
    }
}